inputs.script:
const cleanArg = (v) => { const t = String(v == null ? '' : v).trim(); return /^\{[a-zA-Z0-9_]+\}$/.test(t) ? '' : t; };
const sleep = (ms) => new Promise((resolve) => setTimeout(resolve, ms));
const normalize = (value) => (value || '').replace(/\s+/g, ' ').trim();
const handle = cleanArg(arg0).replace(/^@+/, '').trim().toLowerCase();
const messageText = cleanArg(arg1);
const preview = messageText.slice(0, 80);
if (!handle) throw new Error('recipient_handle is required');
if (!messageText) throw new Error('message_text is required');
if (messageText.length > 1000) return { recipient_handle: handle, message_text_preview: preview, status: 'over_length', length: messageText.length };
if (/login|log in|sign up/i.test(document.title) || document.querySelector('input[name="username"], input[name="enc_password"]')) return { recipient_handle: handle, message_text_preview: preview, status: 'login_required', url: location.href };
let dialog = document.querySelector('[role="dialog"]');
if (!dialog) {
  const newMsgBtn = Array.from(document.querySelectorAll('button, [role="button"]')).find((node) => node.offsetParent && /^(new message|send message)$/i.test(normalize(node.textContent || '')));
  if (!newMsgBtn) return { recipient_handle: handle, message_text_preview: preview, status: 'recipient_not_found', reason: 'No New Message button and no dialog', url: location.href };
  newMsgBtn.click();
  await sleep(1500);
  dialog = document.querySelector('[role="dialog"]');
}
if (!dialog) return { recipient_handle: handle, message_text_preview: preview, status: 'recipient_not_found', reason: 'Dialog did not open', url: location.href };
const queryBox = dialog.querySelector('input[name="queryBox"]');
if (!(queryBox instanceof HTMLInputElement)) return { recipient_handle: handle, message_text_preview: preview, status: 'recipient_not_found', reason: 'queryBox missing', url: location.href };
queryBox.focus();
const valueSetter = Object.getOwnPropertyDescriptor(HTMLInputElement.prototype, 'value').set;
valueSetter.call(queryBox, '');
queryBox.dispatchEvent(new InputEvent('input', { bubbles: true, composed: true, data: null, inputType: 'deleteContentBackward' }));
await sleep(150);
let typed = '';
for (const ch of handle) {
  typed += ch;
  queryBox.dispatchEvent(new KeyboardEvent('keydown', { key: ch, bubbles: true }));
  valueSetter.call(queryBox, typed);
  queryBox.dispatchEvent(new InputEvent('input', { bubbles: true, composed: true, data: ch, inputType: 'insertText' }));
  queryBox.dispatchEvent(new KeyboardEvent('keyup', { key: ch, bubbles: true }));
  await sleep(95);
}
await sleep(2200);
const options = Array.from(dialog.querySelectorAll('[role="option"], label, [role="button"]')).filter((node) => node.offsetParent);
const leafTexts = (node) => {
  const out = [];
  const walk = (n) => {
    if (!n) return;
    if (n.nodeType === 3) { const t = (n.textContent || '').trim(); if (t) out.push(t.toLowerCase()); return; }
    if (n.nodeType !== 1) return;
    for (const child of n.childNodes) walk(child);
  };
  walk(node);
  return out;
};
const exactMatch = options.find((node) => {
  const leaves = leafTexts(node);
  if (leaves.includes(handle)) return true;
  const text = normalize(node.textContent || '').toLowerCase();
  const tokens = text.split(/\s+/);
  return tokens.includes(handle);
});
if (!exactMatch) return { recipient_handle: handle, message_text_preview: preview, status: 'recipient_not_found', visible_options: options.slice(0, 5).map((node) => normalize(node.textContent || '').slice(0, 120)), url: location.href };
exactMatch.scrollIntoView({ block: 'center' });
try { exactMatch.click(); } catch {}
await sleep(700);
const chatBtn = Array.from(dialog.querySelectorAll('button, [role="button"]')).find((node) => /^chat$/i.test(normalize(node.textContent || '')));
if (!chatBtn) return { recipient_handle: handle, message_text_preview: preview, status: 'select_failed', reason: 'No Chat button in dialog', url: location.href };
if (chatBtn.getAttribute('aria-disabled') === 'true' || chatBtn.disabled) return { recipient_handle: handle, message_text_preview: preview, status: 'chat_button_disabled', reason: 'Recipient selection did not enable Chat', url: location.href };
chatBtn.click();
const deadline = Date.now() + 12000;
while (Date.now() < deadline) {
  if (/\/direct\/t\//i.test(location.pathname) && !document.querySelector('[role="dialog"]')) break;
  await sleep(250);
}
if (!/\/direct\/t\//i.test(location.pathname)) return { recipient_handle: handle, message_text_preview: preview, status: 'thread_not_opened', url: location.href };
await sleep(1200);
const composer = document.querySelector('div[contenteditable="true"][aria-label*="Message" i], div[contenteditable="true"][aria-label*="message" i], div[contenteditable="true"][role="textbox"]');
if (!composer) return { recipient_handle: handle, message_text_preview: preview, status: 'composer_not_found', thread_url: location.href };
composer.focus();
try { document.execCommand('insertText', false, messageText); } catch {}
if (!normalize(composer.textContent || '').length) {
  let typedMsg = '';
  for (const ch of messageText) {
    typedMsg += ch;
    composer.dispatchEvent(new KeyboardEvent('keydown', { key: ch, bubbles: true }));
    composer.dispatchEvent(new InputEvent('beforeinput', { bubbles: true, composed: true, data: ch, inputType: 'insertText' }));
    document.execCommand && document.execCommand('insertText', false, ch);
    composer.dispatchEvent(new InputEvent('input', { bubbles: true, composed: true, data: ch, inputType: 'insertText' }));
    composer.dispatchEvent(new KeyboardEvent('keyup', { key: ch, bubbles: true }));
    if (typedMsg.length % 40 === 0) await sleep(15);
  }
}
await sleep(500);
const sendBtn = Array.from(document.querySelectorAll('[role="button"], button')).find((node) => node.offsetParent && /^send$/i.test(normalize(node.getAttribute('aria-label') || node.textContent || '')) && !(node.getAttribute('aria-disabled') === 'true' || node.disabled));
if (sendBtn) { try { sendBtn.click(); } catch {} }
else { composer.dispatchEvent(new KeyboardEvent('keydown', { key: 'Enter', code: 'Enter', keyCode: 13, which: 13, bubbles: true, cancelable: true })); composer.dispatchEvent(new KeyboardEvent('keypress', { key: 'Enter', code: 'Enter', keyCode: 13, which: 13, bubbles: true, cancelable: true })); composer.dispatchEvent(new KeyboardEvent('keyup', { key: 'Enter', code: 'Enter', keyCode: 13, which: 13, bubbles: true, cancelable: true })); }
await sleep(1800);
const composerAfter = document.querySelector('div[contenteditable="true"][aria-label*="Message" i], div[contenteditable="true"][role="textbox"]');
const cleared = !composerAfter || !normalize(composerAfter.textContent || '').length;
if (cleared) return { recipient_handle: handle, message_text_preview: preview, status: 'sent', thread_url: location.href };
return { recipient_handle: handle, message_text_preview: preview, status: 'send_failed', composer_text_after: normalize(composerAfter?.textContent || '').slice(0, 80), thread_url: location.href };
